$ErrorActionPreference = "Stop"
$code = Get-Content -Raw "src\App.jsx"
$code = $code -replace "`r`n", "`n"

$code = $code.Replace(
  "var s40=useState({}); var commentCounts=s40[0]; var setCommentCounts=s40[1];`n`n  var uname = userName(user);",
  "var s40=useState({}); var commentCounts=s40[0]; var setCommentCounts=s40[1];`n  var s69=useState(function(){try{return JSON.parse(localStorage.getItem(`"pm-drafts`")||`"[]`");}catch(e){return [];}}); var drafts=s69[0]; var setDrafts=s69[1];`n`n  React.useEffect(function(){ localStorage.setItem(`"pm-drafts`", JSON.stringify(drafts)); }, [drafts]);`n`n  var uname = userName(user);"
)

$code = $code.Replace(
  "function flash(msg) { setToast(msg); setTimeout(function(){setToast(`"`);},3000); }`n`n  function parseImportFile(file, onDone) {",
  "function flash(msg) { setToast(msg); setTimeout(function(){setToast(`"`);},3000); }`n`n  function saveDraft() {`n    if(!form.name.trim() && !pendingLL) { flash(`"Add a name or location first`"); return; }`n    var draft = {`n      id: `"draft_`"+Date.now(),`n      form: Object.assign({}, form),`n      pendingLL: pendingLL ? {lat: pendingLL.lat, lng: pendingLL.lng} : null,`n      date: new Date().toISOString()`n    };`n    setDrafts(function(d){return [draft].concat(d);});`n    flash(`"Saved to drafts`");`n    setForm({name:`"`",description:`"`",tags:`"`",privacy:`"public`",photo:null,color:`"#2a5d3c`"});`n    setPendingLL(null);`n  }`n`n  function parseImportFile(file, onDone) {"
)

$code = $code.Replace(
  "url:`"https://{s}.tile.openstreetmap.org",
  "url:`"https://a.tile.openstreetmap.org"
).Replace(
  "url:`"https://{s}.tile.opentopomap.org",
  "url:`"https://a.tile.opentopomap.org"
)

$code = $code.Replace(
  "          e(`"path`",{d:`"M12 2v4M12 18v4M2 12h4M18 12h4`",stroke:T.ink2,strokeWidth:1.5,strokeLinecap:`"round`"})`n        )`n      )`n    ),`n`n    // Bottom-left:",
  "          e(`"path`",{d:`"M12 2v4M12 18v4M2 12h4M18 12h4`",stroke:T.ink2,strokeWidth:1.5,strokeLinecap:`"round`"})`n        )`n      ),`n`n      // Offline Download button`n      e(`"button`",{`n        onClick:function(){`n          if(!mapObj.current) return;`n          var b = mapObj.current.getBounds();`n          var zMin = mapZoom > 11 ? mapZoom - 1 : 11;`n          var zMax = 16;`n          var tiles = [];`n          for(var z = zMin; z <= zMax; z++){`n            var pNW = mapObj.current.project(b.getNorthWest(), z);`n            var pSE = mapObj.current.project(b.getSouthEast(), z);`n            var tNW = pNW.divideBy(256).floor();`n            var tSE = pSE.divideBy(256).floor();`n            for(var x = tNW.x; x <= tSE.x; x++){`n              for(var y = tNW.y; y <= tSE.y; y++){`n                if(baseLayer===`"osm`"||baseLayer===`"trails`"||baseLayer===`"seamap`") {`n                  tiles.push(`"https://a.tile.openstreetmap.org/`"+z+`"/`"+x+`"/`"+y+`".png`");`n                  if(baseLayer===`"trails`") tiles.push(`"https://tile.waymarkedtrails.org/hiking/`"+z+`"/`"+x+`"/`"+y+`".png`");`n                  if(baseLayer===`"seamap`") tiles.push(`"https://tiles.openseamap.org/seamark/`"+z+`"/`"+x+`"/`"+y+`".png`");`n                }`n                else if(baseLayer===`"topo`") tiles.push(`"https://a.tile.opentopomap.org/`"+z+`"/`"+x+`"/`"+y+`".png`");`n              }`n            }`n          }`n          tiles = tiles.filter(function(v,i,a){return a.indexOf(v)===i;});`n          if(tiles.length > 8000) { flash(`"Region too large (`"+tiles.length+`" tiles). Zoom in to download.`"); return; }`n          if(!window.confirm(`"Download `"+tiles.length+`" map tiles for offline use?`")) return;`n          flash(`"Downloading `"+tiles.length+`" tiles...`");`n          var loaded = 0;`n          function fetchBatch(idx) {`n            if(idx >= tiles.length) { flash(`"✅ Offline map downloaded!`"); return; }`n            var batch = tiles.slice(idx, idx+20);`n            Promise.all(batch.map(function(url){ return fetch(url,{mode:`"no-cors`"}).catch(function(){}); }))`n              .then(function(){`n                loaded += batch.length;`n                if(loaded % 100 === 0 || loaded === tiles.length) flash(`"Downloading: `" + Math.round((loaded/tiles.length)*100) + `"%`");`n                fetchBatch(idx+20);`n              });`n          }`n          fetchBatch(0);`n        },`n        style:{width:40,height:40,borderRadius:10,`n          background:`"rgba(246,241,228,0.95)`",backdropFilter:`"blur(12px)`",`n          border:`"1px solid `"+T.border,`n          display:`"flex`",alignItems:`"center`",justifyContent:`"center`",cursor:`"pointer`",boxShadow:T.shadow}`n      },`n        e(`"svg`",{width:18,height:18,viewBox:`"0 0 24 24`",fill:`"none`"},`n          e(`"path`",{d:`"M12 4v12m0 0l-4-4m4 4l4-4M4 20h16`",stroke:T.forest,strokeWidth:2,strokeLinecap:`"round`",strokeLinejoin:`"round`"})`n        )`n      )`n    ),`n`n    // Bottom-left:"
)

$code = $code.Replace(
