  "        !user && e(`"div`",{style:{background:T.paper2,border:`"1px solid `"+T.borderSoft,borderRadius:10,padding:14,marginBottom:12,textAlign:`"center`"}},`n          e(`"div`",{style:{fontSize:13,color:T.ink2,marginBottom:8}},`"Sign in to save pins to your account`"),`n          e(`"button`",{style:Object.assign({},S.btn,{width:`"100%`"}),onClick:api.signInGoogle},`"Sign in with Google`")`n        ),`n        drafts.length > 0 && e(`"div`",{style:{marginBottom:16}},`n          e(`"div`",{style:{fontSize:11,color:T.ink3,marginBottom:8}},`"Your Drafts`"),`n          drafts.map(function(d){`n            return e(`"div`",{key:d.id,style:{display:`"flex`",alignItems:`"center`",justifyContent:`"space-between`",padding:`"10px 14px`",background:T.paper2,border:`"1px solid `"+T.borderSoft,borderRadius:10,marginBottom:6,cursor:`"pointer`"},onClick:function(){`n              setForm(d.form);`n              if(d.pendingLL){ setPendingLL(d.pendingLL); if(mapObj.current) mapObj.current.setView([d.pendingLL.lat, d.pendingLL.lng]); }`n              else setPendingLL(null);`n            }},`n              e(`"div`",{style:{flex:1}},`n                e(`"div`",{style:{fontWeight:600,fontSize:14,color:T.ink}},d.form.name || `"Untitled Draft`"),`n                e(`"div`",{style:{fontSize:11,color:T.ink3}},new Date(d.date).toLocaleString())`n              ),`n              e(`"button`",{style:{background:`"none`",border:`"none`",color:`"#c05050`",cursor:`"pointer`",padding:5,fontSize:18,lineHeight:1},onClick:function(ev){ev.stopPropagation();setDrafts(function(ds){return ds.filter(function(x){return x.id!==d.id;});});}},`"×`")`n            );`n          })`n        ),`n        e(`"div`",{style:{position:`"relative`",marginBottom:10}},"
)

$code = $code.Replace(
